/**
 * Generates per-page i18n bundles from the JSON dictionaries.
 *
 * For each page it emits devai-day-workshop/i18n/bundles/<page>.js which assigns
 * the merged common + page dictionaries (for every language) onto window.I18N.
 * These bundles are loaded via <script> so translations work even when the site
 * is opened directly from disk (file://), where fetch() of JSON is blocked.
 *
 * Run from repo root: node devai-day-workshop/i18n/build-bundles.js
 */
const fs = require('fs');
const path = require('path');

const I18N = path.join(__dirname);
const LANGS = ['en', 'nl'];
const OUT = path.join(I18N, 'bundles');

const pages = [
  'index', 'prerequisites', 'start-coding', 'pro-features',
  'extended-capabilities', 'spec-driven-development', 'agentic-workflows', 'copilot-cli',
];

function load(lang, name) {
  return JSON.parse(fs.readFileSync(path.join(I18N, lang, name + '.json'), 'utf8'));
}

fs.mkdirSync(OUT, { recursive: true });

for (const page of pages) {
  const perLang = {};
  for (const lang of LANGS) {
    perLang[lang] = Object.assign({}, load(lang, 'common'), load(lang, page));
  }
  let js = '/* AUTO-GENERATED by i18n/build-bundles.js — do not edit by hand. */\n';
  js += '/* Source of truth: i18n/<lang>/common.json and i18n/<lang>/' + page + '.json */\n';
  js += '(function () {\n  window.I18N = window.I18N || {};\n';
  for (const lang of LANGS) {
    js += '  window.I18N["' + lang + '"] = Object.assign(window.I18N["' + lang + '"] || {}, '
      + JSON.stringify(perLang[lang]) + ');\n';
  }
  js += '})();\n';
  fs.writeFileSync(path.join(OUT, page + '.js'), js);
  console.log('wrote bundles/' + page + '.js  (en ' + Object.keys(perLang.en).length
    + ', nl ' + Object.keys(perLang.nl).length + ' keys)');
}
console.log('Done. ' + pages.length + ' bundle(s) generated.');
